INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('0ae453d150fa2d83', 'NJ', '["federal","state","county"]', 'ballot_access', 'Does New Jersey have an open or closed primary system?', '["New Jersey primary voting rules","Do I have to register with a party to vote in the NJ primary?","Can unaffiliated voters participate in the New Jersey primary?"]', 'New Jersey operates a semi-open (or semi-closed) primary system. Voters who are already registered with a political party may only vote in that party''s primary. However, unaffiliated voters (those who have not declared a party) are permitted to declare a party affiliation at the polls on Primary Day and immediately vote in that party''s primary.', 'https://nj.gov/state/elections/voter-party-affiliation.shtml', 'New Jersey Division of Elections', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('755c321cc0c47753', 'NJ', '["federal","state","county"]', 'runoff_rules', 'Does New Jersey hold primary runoff elections?', '["What is the threshold to win a primary in NJ?","Does New Jersey require a majority to win a primary?","New Jersey primary runoff rules"]', 'No. New Jersey does not hold primary runoff elections. A candidate does not need to secure a 50%+1 majority to win the party''s nomination; the candidate who receives a simple plurality (the most votes) in the primary advances directly to the general election.', 'https://nj.gov/state/elections/', 'New Jersey Division of Elections', '2026-05-17', 'static', 'official_source_direct', 'All primary candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('124f4b1077c86d86', 'NJ', '["federal","state","county"]', 'ballot_access', 'Are write-in candidates permitted in New Jersey?', '["Do write-in votes count in NJ?","How to register as a write-in candidate in New Jersey","Write-in filing deadline New Jersey"]', 'Yes. Write-in votes are permitted in both primary and general elections. However, to be officially nominated via a write-in campaign in a primary election, the candidate must receive at least the number of write-in votes equivalent to the number of signatures required on a standard nominating petition for that specific office.', 'https://nj.gov/state/elections/candidate-information.shtml', 'New Jersey Division of Elections', '2026-05-17', 'static', 'official_source_direct', 'Write-in candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('1ae3fa991dd85072', 'NJ', '["federal","state","county"]', 'filing_requirements', 'What is the candidate filing deadline for New Jersey in 2026?', '["When do candidates file for office in New Jersey?","New Jersey filing deadline 2026","March filing deadline NJ"]', 'For major party candidates participating in the 2026 primary election, the statutory filing deadline is the 71st day before the primary election. For the June 2, 2026 primary, the filing deadline was March 23, 2026.', 'https://nj.gov/state/elections/election-chronological-timelines.shtml', 'New Jersey Division of Elections - Timelines', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('1e127426e5b27434', 'NJ', '["federal","state"]', 'ballot_access', 'What is the petition signature threshold for independent candidates in New Jersey?', '["Independent candidate ballot access New Jersey","Running without a party in NJ 2026","How many signatures for independent US Senate NJ"]', 'Independent (direct nomination) candidates seeking statewide office, such as the U.S. Senate, must submit a petition containing at least 800 valid signatures from registered voters. For U.S. House of Representatives candidates, the requirement is 100 valid signatures from voters within the district. The deadline to file is the day of the primary election.', 'https://nj.gov/state/elections/candidate-information.shtml', 'New Jersey Division of Elections - Candidate Guidelines', '2026-05-17', 'static', 'official_source_direct', 'Independent candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('98668a48d652ecd8', 'NJ', '["federal","state","county"]', 'ballot_access', 'Does New Jersey have a sore loser law?', '["Can I run as an independent if I lose the NJ primary?","New Jersey sore loser statute","General election ballot access after primary defeat NJ"]', 'Yes. New Jersey strictly enforces a sore loser law under N.J.S.A. 19:13-8. A candidate who seeks a party''s nomination in the primary election and is defeated is prohibited from subsequently running as an independent candidate for the same office in the ensuing general election.', 'https://law.justia.com/codes/new-jersey/title-19/section-19-13-8/', 'New Jersey Statutes Annotated 19:13-8', '2026-05-17', 'static', 'statute_citation', 'Major party candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('0ec83419e3994654', 'NJ', '["state"]', 'ballot_access', 'Do the Governor and Lieutenant Governor run on a joint ticket in New Jersey?', '["New Jersey joint ticket rules","How are Lt Gov candidates selected in NJ?","Does the Governor pick a running mate in New Jersey?"]', 'Yes. Following a constitutional amendment passed in 2005 (first effective in 2009), the Governor and Lieutenant Governor of New Jersey run on a joint ticket in the general election. The gubernatorial nominee selects their Lieutenant Governor running mate within 30 days after winning the primary election.', 'https://nj.gov/state/elections/', 'New Jersey Division of Elections', '2026-05-17', 'static', 'official_source_direct', 'Statewide executive candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('445e490bfce689a5', 'NJ', '["federal","state","county"]', 'election_dates', 'When are the primary and general elections in New Jersey for 2026?', '["New Jersey primary date 2026","When is Election Day 2026 in New Jersey?","June primary New Jersey"]', 'The New Jersey primary election will be held on Tuesday, June 2, 2026. The general election will be held on Tuesday, November 3, 2026. Polls are open statewide from 6:00 a.m. to 8:00 p.m. local time.', 'https://nj.gov/state/elections/', 'New Jersey Division of Elections', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('435707a475f2df60', 'NJ', '["state"]', 'election_dates', 'Is the New Jersey Governor running for election in 2026?', '["New Jersey Governor election 2026","Who is defending the NJ Governor seat?","Gubernatorial race New Jersey 2026"]', 'No. New Jersey is one of only two states (along with Virginia) that elects its Governor strictly in odd-numbered years following presidential elections. The New Jersey gubernatorial election occurs in 2025 and 2029; there is NO gubernatorial race on the 2026 midterm ballot.', 'https://ballotpedia.org/Governor_of_New_Jersey', 'Ballotpedia - Governor of New Jersey', '2026-05-17', 'static', 'secondary_source', 'Statewide candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('d2c845bde6696ee7', 'NJ', '["federal"]', 'election_dates', 'Which U.S. Senate seat is up for election in New Jersey in 2026?', '["Is Cory Booker up for re-election in 2026?","When is Andy Kim''s next election?","New Jersey US Senate cycle 2026"]', 'The Class 2 U.S. Senate seat currently held by Cory Booker (D) is up for election in 2026. Senator Andy Kim (Class 1) was elected in 2024 to fill the seat formerly held by Bob Menendez, and he will not appear on the ballot again until 2030.', 'https://www.senate.gov/senators/Class_II.htm', 'U.S. Senate - Class II Senators', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('34261422f2afd5a8', 'NJ', '["federal"]', 'election_dates', 'Is Senator Andy Kim up for re-election in 2026?', '["Andy Kim Senate term length","New Jersey Class 1 Senate election","Is Andy Kim on the 2026 ballot?"]', 'No. Senator Andy Kim holds the Class 1 U.S. Senate seat for New Jersey. He was elected in November 2024 and his current term runs until January 2031, meaning he will not be on the 2026 ballot.', 'https://www.senate.gov/senators/Class_I.htm', 'U.S. Senate - Class I Senators', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('cebb07637a20a37a', 'NJ', '["federal"]', 'election_dates', 'How many U.S. House districts are in New Jersey for the 2026 election?', '["New Jersey congressional apportionment","Are all NJ congressional seats up in 2026?","Number of US Representatives from New Jersey"]', 'New Jersey is apportioned 12 U.S. House districts. All 12 seats are on the 2026 ballot, as U.S. Representatives serve two-year terms.', 'https://nj.gov/state/elections/', 'New Jersey Division of Elections', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('49a2483b03097e8e', 'NJ', '["state"]', 'election_dates', 'Which New Jersey State Legislature seats are up for election in 2026?', '["Are all New Jersey Assembly seats up in 2026?","New Jersey Senate election cycle 2026","Which legislative districts are on the ballot in NJ?"]', 'None. The entire New Jersey Legislature (all 40 State Senate seats and all 80 General Assembly seats) is elected strictly in odd-numbered years, aligned with the gubernatorial cycle (e.g., 2025, 2027). There are ZERO regular state legislative elections on the 2026 midterm ballot, making it an unusually federal- and local-focused year in NJ.', 'https://njleg.state.nj.us/', 'New Jersey Legislature', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('749b7f7fc668066a', 'NJ', '["state"]', 'election_dates', 'Which statewide executive offices are elected by voters in New Jersey?', '["Is the Attorney General up in 2026?","NJ statewide election list 2026","When is the Secretary of State election in NJ?"]', 'In New Jersey, the Governor and Lieutenant Governor are the ONLY statewide executive officers elected by the voters. The Attorney General and Secretary of State are appointed by the Governor with Senate confirmation, and the State Treasurer is appointed by the Governor. Therefore, there are NO statewide executive offices on the 2026 ballot.', 'https://nj.gov/nj/gov/dept/', 'State of New Jersey - Departments and Agencies', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('6f07f7a7dff58ae9', 'NJ', '["judicial"]', 'election_dates', 'How are New Jersey Supreme Court justices selected and are they on the ballot?', '["New Jersey judicial elections 2026","Are NJ judges elected or appointed?","Supreme Court elections New Jersey"]', 'New Jersey does NOT hold judicial elections. Supreme Court justices and most state judges are appointed by the Governor and confirmed by the State Senate for an initial seven-year term. If re-appointed, they may serve until the mandatory retirement age of 70. They never appear on a public ballot.', 'https://www.njcourts.gov/courts/supreme', 'New Jersey Courts', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('0af7739540dac253', 'NJ', '["state"]', 'election_dates', 'What is the schedule for the New Jersey State Legislature sessions?', '["When does the NJ legislature meet?","New Jersey full-time legislature","Legislative session length New Jersey"]', 'The New Jersey Legislature is one of the few full-time (or near full-time) legislatures in the country. It meets throughout the entire year, convening on the second Tuesday in January of even-numbered years for a two-year session, with meetings and committee work scheduled year-round.', 'https://njleg.state.nj.us/', 'New Jersey Legislature', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('39c5fe882d8648bf', 'NJ', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Governor of New Jersey?', '["Age and residency for New Jersey Governor","New Jersey Constitution Governor qualifications","Who is eligible to be Governor of NJ?"]', 'Under Article V of the New Jersey Constitution, a candidate for Governor must be at least 30 years old, a citizen of the United States for at least 20 years, and a resident of New Jersey for at least seven years continuously preceding their election.', 'https://nj.gov/state/elections/candidate-information.shtml', 'New Jersey Division of Elections - Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'Gubernatorial candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('8a06dbc026fed2e4', 'NJ', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for the New Jersey State Legislature?', '["Qualifications for NJ State Assembly","Age requirement New Jersey State Senate","Do I have to live in my district to run in NJ?"]', 'A candidate for the State Senate must be at least 30 years old. A candidate for the General Assembly must be at least 21 years old. Both must be citizens and residents of New Jersey for at least two years, and residents of their respective legislative district for at least one year prior to the election.', 'https://nj.gov/state/elections/candidate-information.shtml', 'New Jersey Division of Elections - Qualifications', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('999036603abdb4fc', 'NJ', '["federal"]', 'candidate_eligibility', 'What are the eligibility requirements for U.S. House and Senate candidates in New Jersey?', '["US Senate residency requirements New Jersey","Age to run for Congress in New Jersey","Federal constitutional requirements for NJ candidates"]', 'Federal candidates must meet standard U.S. Constitutional requirements: U.S. House members must be at least 25 years old, a U.S. citizen for 7 years, and an inhabitant of the state when elected. U.S. Senators must be at least 30 years old, a U.S. citizen for 9 years, and an inhabitant of the state when elected.', 'https://nj.gov/state/elections/candidate-information.shtml', 'New Jersey Division of Elections', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('a6ea683239452b67', 'NJ', '["state"]', 'candidate_eligibility', 'What are the term limits for the New Jersey Governor?', '["How many terms can a New Jersey Governor serve?","New Jersey executive term limit law","Phil Murphy term limits NJ"]', 'Under the New Jersey Constitution, the Governor is limited to serving two consecutive four-year terms. After serving two consecutive terms, an individual is ineligible to run for the office again until a full four-year term has intervened.', 'https://ballotpedia.org/Governor_of_New_Jersey', 'New Jersey Constitution', '2026-05-17', 'static', 'secondary_source', 'Gubernatorial candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('0d5383e422bb6b01', 'NJ', '["state"]', 'candidate_eligibility', 'How is the Attorney General selected in New Jersey, and what are the qualifications?', '["Qualifications to run for Attorney General in NJ","Is the Attorney General elected in New Jersey?","Legal requirements for New Jersey Attorney General"]', 'The Attorney General of New Jersey is NOT an elected position. The Attorney General is appointed by the Governor with the advice and consent of the State Senate and serves concurrently with the Governor''s term. The appointee must be a licensed attorney in the state.', 'https://www.njoag.gov/about/', 'New Jersey Office of the Attorney General', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('42aa0fcfe72e6d16', 'NJ', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for State Treasurer or Secretary of State in New Jersey?', '["New Jersey Secretary of State requirements","Is the Treasurer elected in NJ?","Qualifications for Secretary of State New Jersey"]', 'Neither the State Treasurer nor the Secretary of State are elected by voters in New Jersey. Both officials are appointed directly by the Governor, with the advice and consent of the State Senate, and serve at the pleasure of the Governor.', 'https://nj.gov/nj/gov/dept/', 'State of New Jersey', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('a24d3b20ed3da446', 'NJ', '["federal","state","county","municipal"]', 'voter_interaction', 'Is a photo ID required to vote in person in New Jersey?', '["New Jersey voter ID requirements","Do I need my driver''s license to vote in NJ?","Acceptable ID for New Jersey voting"]', 'No. New Jersey DOES NOT require voters to present a photo ID to vote in person at the polls. Election workers verify voter identity by matching the signature in the poll book with the signature the voter provides at the polling place. (ID is only required for certain first-time voters who registered by mail without providing a driver''s license or SSN).', 'https://nj.gov/state/elections/voter-id.shtml', 'New Jersey Division of Elections - Voter ID', '2026-05-17', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('9abc214ad9a04ea2', 'NJ', '["federal","state","county","municipal"]', 'voter_interaction', 'Is New Jersey a universal mail ballot state, and is no-excuse absentee voting allowed?', '["Do all voters get a mail ballot in New Jersey?","New Jersey vote-by-mail system","Do I need an excuse to vote absentee in NJ?"]', 'New Jersey is not a strictly universal mail ballot state (ballots are not automatically sent to all voters by default), but it has a broad no-excuse ''Vote By Mail'' system. Any registered voter may request a mail-in ballot without providing an excuse, and voters can opt to receive mail ballots for all future elections automatically.', 'https://nj.gov/state/elections/vote-by-mail.shtml', 'New Jersey Division of Elections - Vote by Mail', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('7fbde12fdc28c3dc', 'NJ', '["federal","state","county","municipal"]', 'voter_interaction', 'Does New Jersey offer early in-person voting?', '["Can I vote early in person in NJ?","New Jersey early voting dates 2026","When does early voting start in New Jersey?"]', 'Yes. New Jersey offers true no-excuse early in-person voting using voting machines. For the general election, the early voting period lasts 9 days, ending the Sunday before Election Day. For the primary election, the early voting period is 5 days, also ending the Sunday before Election Day.', 'https://nj.gov/state/elections/vote-early-voting.shtml', 'New Jersey Division of Elections - Early Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('03317d2997b37d56', 'NJ', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the voter registration deadline and does New Jersey offer same-day registration?', '["Last day to register to vote in NJ","New Jersey same day voter registration","Voter registration deadline 2026 New Jersey"]', 'The deadline to register to vote in New Jersey is 21 days before the election. Registration can be completed online, by mail, or in person. New Jersey DOES NOT currently offer same-day voter registration at the polls on Election Day or during early voting.', 'https://nj.gov/state/elections/voter-registration.shtml', 'New Jersey Division of Elections - Voter Registration', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('fc1c0fd6f959a2e1', 'NJ', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the electioneering buffer zone distance in New Jersey?', '["How close can I campaign to a polling place in NJ?","New Jersey 100 feet electioneering rule","NJ buffer zone around voting centers"]', 'Under New Jersey law (N.J.S.A. 19:34-15), electioneering is strictly prohibited within 100 feet of the outside entrance to any polling place or early voting site. This bans the distribution of campaign literature, displaying signs, and soliciting votes within this zone.', 'https://law.justia.com/codes/new-jersey/title-19/section-19-34-15/', 'New Jersey Statutes Annotated 19:34-15', '2026-05-17', 'static', 'statute_citation', 'Campaign workers and Voters', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('0ec2c76a6579b706', 'NJ', '["federal","state","county","municipal"]', 'voter_interaction', 'How are voting rights restored for individuals with felony convictions in New Jersey?', '["Can felons vote in New Jersey state?","Felony voting rights restoration NJ","Voting on parole in New Jersey"]', 'Following a 2019 law, New Jersey restores voting rights to individuals convicted of a felony immediately upon their release from prison. Individuals who are on probation or parole are fully eligible to register and vote.', 'https://nj.gov/state/elections/voter-registration.shtml', 'New Jersey Division of Elections', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('816031e55cde6dd8', 'NJ', '["county"]', 'voter_interaction', 'How many counties are in New Jersey, and why does it matter for campaigns?', '["New Jersey county election administration","How many county clerks in NJ?","Local election control New Jersey"]', 'New Jersey has 21 counties. Election administration is heavily decentralized to the county level, handled jointly by the County Clerk, the Board of Elections, and the Superintendent of Elections. Campaigns must coordinate with these 21 jurisdictions regarding ballot layout, mail voting, and early voting logistics.', 'https://nj.gov/state/elections/county-eo.shtml', 'New Jersey Division of Elections - County Officials', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('6ffd4589850d68ac', 'NJ', '["state","county","municipal"]', 'finance_ethics', 'Which agency administers campaign finance tracking in New Jersey?', '["Where do I file campaign finance reports in NJ?","What is the New Jersey ELEC?","Does the NJ Secretary of State handle campaign finance?"]', 'Campaign finance and disclosure laws in New Jersey are administered and enforced by the New Jersey Election Law Enforcement Commission (ELEC), an independent regulatory agency separate from the Division of Elections.', 'https://www.elec.nj.gov/', 'New Jersey Election Law Enforcement Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('f647b0d0abebf2b2', 'NJ', '["state","county"]', 'finance_ethics', 'What are the individual campaign contribution limits in New Jersey?', '["Are there contribution limits in New Jersey?","NJ individual donation caps 2026 election","Elections Transparency Act limits NJ"]', 'Following the 2023 Elections Transparency Act, individual contribution limits in New Jersey were significantly raised. Individuals may contribute up to $5,200 per election to a candidate for non-gubernatorial office (like State Senate or local). Contributions to gubernatorial candidates are capped at $5,800 per election.', 'https://www.elec.nj.gov/pdffiles/Limits_chart.pdf', 'New Jersey Election Law Enforcement Commission (ELEC)', '2026-05-17', 'per_cycle', 'official_source_direct', 'Candidates and Donors', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('34f688986dd602ca', 'NJ', '["state","county","municipal"]', 'finance_ethics', 'Are corporate contributions permitted in New Jersey campaigns?', '["Corporate contribution ban New Jersey state","Can a business donate to my campaign in NJ?","Corporate campaign finance rules New Jersey"]', 'Yes. Direct contributions from corporations to candidates are permitted in New Jersey. However, they are subject to the exact same contribution limits as individual donors ($5,200 per election for most offices, $5,800 for Governor). Note that ''Pay-to-Play'' laws strictly regulate contributions from businesses holding government contracts.', 'https://www.elec.nj.gov/pdffiles/Limits_chart.pdf', 'New Jersey ELEC - Contribution Limits', '2026-05-17', 'static', 'official_source_direct', 'Candidates and Businesses', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('8d969e530302d4db', 'NJ', '["state","county","municipal"]', 'finance_ethics', 'What is the general campaign finance reporting schedule for New Jersey candidates?', '["NJ ELEC filing dates 2026","When are campaign finance reports due in NJ?","New Jersey pre-primary and pre-general report deadlines"]', 'For candidates appearing on the ballot, reports must be filed 29 days before the election, 11 days before the election, and 20 days after the election. If the candidate committee remains active but the candidate is not on the ballot that year, they file quarterly reports.', 'https://www.elec.nj.gov/pdffiles/filing_dates/2026_dates.pdf', 'New Jersey ELEC - Filing Dates', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('55360e8d1001dfdd', 'NJ', '["state","county","municipal"]', 'finance_ethics', 'What are New Jersey''s rapid disclosure requirements for late contributions?', '["New Jersey 48-hour large contribution report","Late contribution reporting New Jersey ELEC","When do I file a rapid report in NJ?"]', 'Under ELEC rules, if a candidate committee receives a contribution or loan in excess of $2,000 during the 13 days prior to an election up to Election Day, they must file a rapid disclosure ''48-Hour Notice'' with the Commission within 48 hours of receipt.', 'https://www.elec.nj.gov/pdffiles/compliance_manuals/manual_c.pdf', 'New Jersey ELEC - Compliance Manual', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('e496a9f598814319', 'NJ', '["state"]', 'finance_ethics', 'Does New Jersey provide public financing for state campaigns?', '["Public matching funds for New Jersey Governor","State funded campaigns New Jersey status","Government campaign grants NJ"]', 'Yes, but exclusively for gubernatorial campaigns. New Jersey offers a Gubernatorial Public Financing Program where qualifying candidates for Governor (who raise a minimum threshold of private contributions) can receive two-for-one public matching funds, subject to strict expenditure limits.', 'https://www.elec.nj.gov/publicinformation/gubernatorial_finance.htm', 'New Jersey ELEC - Gubernatorial Finance', '2026-05-17', 'static', 'official_source_direct', 'Gubernatorial candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('9781b32ec990eb31', 'NJ', '["state"]', 'finance_ethics', 'Is there a session freeze on campaign contributions for New Jersey legislators?', '["Can New Jersey legislators raise money during session?","Lobbyist contribution ban NJ legislature","Legislative session contribution rules New Jersey"]', 'No, New Jersey does not have a general ''session freeze'' that prohibits legislators from accepting campaign contributions while the legislature is in session (which is year-round). However, state law strictly prohibits soliciting or accepting political contributions on state property at any time.', 'https://www.elec.nj.gov/pdffiles/compliance_manuals/manual_c.pdf', 'New Jersey ELEC', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates and Lobbyists', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('6789eb820c8ef6e9', 'NJ', '["state","county"]', 'finance_ethics', 'What are the PAC contribution limits to candidates in New Jersey?', '["NJ PAC donation limits to candidates 2026","Political committee vs individual contribution limit New Jersey","Maximum PAC gift to state legislator NJ"]', 'Following the 2023 Elections Transparency Act, PACs (officially Continuing Political Committees) have significantly higher contribution limits than individuals. A PAC may contribute up to $17,300 per election to a non-gubernatorial candidate committee, compared to the $5,200 limit for individuals and corporations.', 'https://www.elec.nj.gov/pdffiles/Limits_chart.pdf', 'New Jersey ELEC - Contribution Limits', '2026-05-17', 'per_cycle', 'official_source_direct', 'State and County candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('29e1f40a37f9fe09', 'NJ', '["federal","state"]', 'redistricting', 'Who draws New Jersey''s congressional and state legislative maps?', '["Does the NJ legislature draw district maps?","Who has the authority to draw district lines in New Jersey?","New Jersey redistricting commission"]', 'In New Jersey, the state legislature does NOT draw district maps. Instead, the state uses two independent, bipartisan commissions: the 11-member Apportionment Commission handles state legislative districts, and the 13-member Redistricting Commission handles congressional districts. Both utilize tie-breaking independent chairs.', 'https://ballotpedia.org/Redistricting_in_New_Jersey', 'Ballotpedia - Redistricting in New Jersey', '2026-05-17', 'static', 'secondary_source', 'Federal and State candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('496d44bf74e86927', 'NJ', '["federal","state"]', 'redistricting', 'What are the legal criteria for redistricting in New Jersey?', '["Standards for drawing New Jersey district lines","New Jersey gerrymandering rules","Map requirements NJ"]', 'Under the New Jersey Constitution, state legislative districts must be contiguous, compact, and as nearly equal in population as possible, without dividing municipalities unless necessary for population equality. Federal districts must comply with the Voting Rights Act and equal population standards.', 'https://ballotpedia.org/Redistricting_in_New_Jersey', 'New Jersey Constitution', '2026-05-17', 'static', 'statute_citation', 'Federal and State candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('7e18df1a768c0c11', 'NJ', '["federal","state"]', 'redistricting', 'Are the current New Jersey redistricting maps operative for the 2026 cycle?', '["Status of New Jersey congressional redistricting maps","Are there pending redistricting lawsuits in New Jersey?","New Jersey 2026 legislative boundaries"]', 'Yes. The maps adopted by the independent commissions in late 2021 and early 2022 remain fully operative for the 2026 election cycle. There have been no successful VRA or partisan gerrymandering challenges overturning them.', 'https://www.njredistrictingcommission.org/', 'New Jersey Redistricting Commission', '2026-05-17', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('87c0f82752a02fff', 'NJ', '["state","county","municipal"]', 'finance_ethics', 'What is the New Jersey Pay-to-Play law?', '["NJ government contract contribution limits","Pay-to-play campaign finance rules New Jersey","Can a government contractor donate to a campaign in NJ?"]', 'New Jersey enforces strict ''Pay-to-Play'' laws designed to limit the influence of businesses with government contracts. Under state law, businesses seeking or holding state or local government contracts over $17,500 are heavily restricted from making campaign contributions (typically capped at $300) to candidates or committees overseeing those contracts.', 'https://www.elec.nj.gov/pay2play/p2p.html', 'New Jersey ELEC - Pay-to-Play', '2026-05-17', 'static', 'official_source_direct', 'Candidates and Businesses', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('e3ad948d0b8dce9a', 'NJ', '["state"]', 'recall_rules', 'Does New Jersey have a recall mechanism for state officials?', '["Can the Governor of New Jersey be recalled?","How to recall a state senator in NJ","Statewide recall election rules New Jersey"]', 'Yes. Article I, Paragraph 2b of the New Jersey Constitution allows voters to recall any state-level elected official after their first year in office. Proponents must gather signatures equal to 25% of the registered voters who voted in the last general election, within 320 days for a Governor or U.S. Senator, or 160 days for other officials.', 'https://law.justia.com/codes/new-jersey/title-19/section-19-27a-2/', 'New Jersey Revised Statutes § 19:27A-2', '2026-05-17', 'static', 'statute_citation', 'Statewide and legislative candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('0a8a6fdf7777a899', 'NJ', '["county","municipal"]', 'recall_rules', 'What are the rules for local recall in New Jersey?', '["New Jersey county commissioner recall rules","Signature requirement local recall New Jersey","Recalling a mayor in NJ"]', 'Yes. The same constitutional recall provision that applies to state officials also applies to local elected officials in New Jersey. Residents may recall local officials by gathering signatures from 25% of the voters who voted in the last general election within a 160-day period.', 'https://law.justia.com/codes/new-jersey/title-19/section-19-27a-2/', 'New Jersey Revised Statutes § 19:27A-2', '2026-05-17', 'static', 'statute_citation', 'Local candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('093fffe52b60f93b', 'NJ', '["state"]', 'ballot_access', 'Does New Jersey have a citizen initiative process?', '["How to get an initiative on the NJ ballot","New Jersey citizen initiative signature requirements","Can citizens propose laws in New Jersey?"]', 'No. New Jersey is one of the states that does NOT have a statewide citizen initiative process. Citizens cannot draft statutes or constitutional amendments and gather signatures to place them on the ballot. All statewide ballot measures must be referred by the state legislature.', 'https://ballotpedia.org/Initiative_and_referendum_in_New_Jersey', 'Ballotpedia - Initiative and Referendum in New Jersey', '2026-05-17', 'static', 'secondary_source', 'Ballot measure committees', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('99a305074056a5af', 'NJ', '["state"]', 'ballot_access', 'How does the New Jersey legislature refer a constitutional amendment to the voters?', '["Legislative referral process New Jersey","Referendum by legislature NJ","Can the NJ legislature put a constitutional amendment on the ballot?"]', 'The New Jersey Legislature can refer a constitutional amendment to the ballot in two ways: either by securing a three-fifths (60%) supermajority vote in both chambers during a single legislative session, OR by securing a simple majority vote in both chambers in two consecutive legislative sessions.', 'https://ballotpedia.org/Amending_the_New_Jersey_Constitution', 'New Jersey Constitution Article IX', '2026-05-17', 'static', 'statute_citation', 'Legislators and Strategists', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('d3ae438cb69ee78a', 'NJ', '["state"]', 'ballot_access', 'Does New Jersey have a veto referendum process?', '["How to refer a NJ bill to the ballot","New Jersey citizen referendum rules","Veto referendum signature threshold New Jersey state"]', 'No. New Jersey does not have a statewide veto referendum process. Citizens cannot gather signatures to suspend and refer an already-passed legislative act to the ballot for a popular vote of approval or rejection.', 'https://ballotpedia.org/Initiative_and_referendum_in_New_Jersey', 'Ballotpedia - Initiative and Referendum in New Jersey', '2026-05-17', 'static', 'secondary_source', 'Ballot measure committees', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('810ae79ed61d94d8', 'NJ', '["state"]', 'ballot_access', 'What voter approval threshold is required to pass ballot measures in New Jersey?', '["New Jersey ballot measure pass threshold","Does a measure need a supermajority in NJ?","Majority vote requirements New Jersey ballot measures"]', 'In New Jersey, a legislatively referred constitutional amendment or bond measure requires only a simple majority (over 50%) of the total votes cast on that specific measure to pass and become law.', 'https://nj.gov/state/elections/', 'New Jersey Division of Elections', '2026-05-17', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('8275026d00641f32', 'NJ', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Lieutenant Governor in New Jersey?', '["New Jersey Lt Gov requirements","Does the Lt Gov have the same requirements as the Governor in NJ?","Qualifications for Lieutenant Governor of New Jersey"]', 'Under Article V of the New Jersey Constitution, the qualifications for Lieutenant Governor are identical to those for Governor. A candidate must be at least 30 years old, a U.S. citizen for 20 years, and a resident of New Jersey for seven years.', 'https://nj.gov/state/elections/candidate-information.shtml', 'New Jersey Division of Elections', '2026-05-17', 'static', 'official_source_direct', 'Statewide executive candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('b5961bd31c4a6aa9', 'NJ', '["state"]', 'candidate_eligibility', 'How is the Secretary of State selected in New Jersey, and what are the qualifications?', '["Requirements to run for NJ Secretary of State","Who can run for Secretary of State in NJ?","Is the Secretary of State elected in New Jersey?"]', 'The Secretary of State is NOT elected by voters in New Jersey. The Secretary is appointed by the Governor with the advice and consent of the State Senate, and serves concurrently with the Governor''s term. There are no specific constitutional age or residency requirements explicitly enumerated for this office.', 'https://nj.gov/state/about-sos.shtml', 'New Jersey Department of State', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('e946369568bae796', 'NJ', '["municipal"]', 'candidate_eligibility', 'What are the eligibility requirements for a school board candidate in New Jersey?', '["Run for school board New Jersey requirements","Who can be a school board member in NJ?","School board residency rules New Jersey"]', 'To run for a local school board in New Jersey, a candidate must be a registered voter in the district, a resident of the district for at least one year immediately preceding the election, able to read and write, and must pass a criminal background check (not disqualified by certain convictions).', 'https://www.njsba.org/about/membership/school-board-candidacy/', 'New Jersey School Boards Association', '2026-05-17', 'static', 'secondary_source', 'School board candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('902025c08a6b571d', 'NJ', '["county"]', 'candidate_eligibility', 'What are the eligibility requirements to run for County Sheriff in New Jersey?', '["Qualifications for New Jersey Sheriff","Run for Sheriff in NJ","County Sheriff residency requirements New Jersey"]', 'To run for County Sheriff in New Jersey, a candidate must be a citizen of the United States and a resident of the county they seek to serve for at least three years immediately preceding the election.', 'https://nj.gov/state/elections/candidate-information.shtml', 'New Jersey Division of Elections - Qualifications', '2026-05-17', 'static', 'official_source_direct', 'County candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('4de5ca0d51fc0922', 'NJ', '["county"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Surrogate in New Jersey?', '["Qualifications for New Jersey Surrogate","Run for Surrogate in NJ","County Surrogate term length New Jersey"]', 'The Surrogate is a constitutional officer elected by the voters of the county to a five-year term. A candidate must be a registered voter and a resident of the county they seek to serve.', 'https://nj.gov/state/elections/candidate-information.shtml', 'New Jersey Division of Elections - Qualifications', '2026-05-17', 'static', 'official_source_direct', 'County candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('16bf3f096af455b1', 'NJ', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the ballot signature cure process for absentee mail-in ballots in New Jersey?', '["How to fix a rejected signature in NJ","New Jersey ballot cure process deadline","Missing signature on NJ mail ballot"]', 'Under the Ballot Cure Act of 2020, if a county board of elections identifies a missing or mismatched signature on a mail-in ballot, they must send the voter a ''Cure Letter'' detailing the issue. The voter then has until 48 hours prior to the final certification of the election to return a Cure Form and an acceptable ID to have their ballot counted.', 'https://nj.gov/state/elections/vote-by-mail.shtml', 'New Jersey Division of Elections - Vote by Mail', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('cd1938f31f85cf1f', 'NJ', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the deadlines for military and overseas (UOCAVA) voters in New Jersey?', '["When are military ballots due in New Jersey?","UOCAVA return deadline NJ","Overseas voting rules New Jersey state"]', 'Under UOCAVA, ballots are transmitted to military and overseas voters at least 45 days before an election. Voted ballots returned by mail must be postmarked by Election Day and received by the county board of elections within 144 hours (6 days) after the close of polls to be counted. If transmitted electronically, they must be received by 8:00 p.m. on Election Day.', 'https://nj.gov/state/elections/vote-military-and-overseas.shtml', 'New Jersey Division of Elections - UOCAVA', '2026-05-17', 'static', 'official_source_direct', 'UOCAVA voters', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('b318312f706a66f6', 'NJ', '["federal","state","county","municipal"]', 'voter_interaction', 'When are provisional ballots used in New Jersey and how are they cured?', '["What is a provisional ballot in NJ?","Voting without ID New Jersey","When do election workers issue provisional ballots?"]', 'Provisional ballots are issued if a voter''s eligibility is in question, if they moved without updating their address, or if they requested a mail-in ballot but decided to vote in person instead. If a provisional ballot is cast because the voter lacked required first-time voter ID, the voter must provide the required ID to the county board within 48 hours after the election for the ballot to count.', 'https://nj.gov/state/elections/vote-provisional-ballot.shtml', 'New Jersey Division of Elections - Provisional Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Poll Watchers', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('196ee136b86ea35d', 'NJ', '["federal","state","county","municipal"]', 'voter_interaction', 'Does New Jersey have Automatic Voter Registration (AVR) at the DMV?', '["Is registration automatic at the New Jersey MVC?","NJ motor voter automatic registration","Do I have to register to vote if I get an NJ driver''s license?"]', 'Yes. New Jersey implemented Automatic Voter Registration (AVR). Eligible individuals conducting business at the Motor Vehicle Commission (MVC) or other designated state agencies are automatically registered to vote or have their registration updated, unless they actively decline (opt-out) during the transaction.', 'https://nj.gov/state/elections/voter-registration.shtml', 'New Jersey Division of Elections', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('0d8104ddab103bc9', 'NJ', '["federal","state","county","municipal"]', 'voter_interaction', 'Does New Jersey offer Online Voter Registration?', '["Can I register to vote online in NJ?","New Jersey electronic voter registration","NJ online registration portal"]', 'Yes. Eligible New Jersey residents who possess an MVC-issued driver''s license or non-driver ID card, or a Social Security Number, can securely register to vote or update their registration using the Division of Elections'' online voter registration system.', 'https://voter.svrs.nj.gov/register', 'New Jersey Division of Elections - OVR', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('c6e4e59b2d3492df', 'NJ', '["federal","state","county","municipal"]', 'voter_interaction', 'How does New Jersey maintain its voter registration lists?', '["NJ voter list maintenance rules","How are inactive voters handled in New Jersey?","New Jersey voter roll cleaning process"]', 'New Jersey maintains its voter rolls using the Electronic Registration Information Center (ERIC) to identify voters who have moved or died. The state also utilizes National Change of Address (NCOA) data. Voters who are mailed confirmation notices and fail to respond or vote over two consecutive federal election cycles are removed from the active registry.', 'https://nj.gov/state/elections/', 'New Jersey Division of Elections', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('988d72a0393980b9', 'NJ', '["federal","state","county","municipal"]', 'voter_interaction', 'How can campaigns access the New Jersey voter file?', '["New Jersey voter database access cost","How to get the voter list in NJ","What data is included in the New Jersey voter file?"]', 'Campaigns and political committees can request the statewide voter registration list (Statewide Voter Registration System - SVRS) by submitting an application to the Division of Elections and paying an administrative fee. The data is legally restricted to electoral and political purposes and may not be used for commercial solicitation.', 'https://nj.gov/state/elections/voter-information-request.shtml', 'New Jersey Division of Elections - Voter Information', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('b1f6c5c575954292', 'NJ', '["state","county","municipal"]', 'runoff_rules', 'Is Ranked Choice Voting (RCV) used in New Jersey?', '["Does New Jersey use ranked choice voting?","RCV status in New Jersey 2026","Instant runoff voting NJ"]', 'Ranked Choice Voting (RCV) is not used for statewide or federal elections in New Jersey. However, under state law, certain municipalities may adopt it for local nonpartisan elections. For example, the city of Hoboken has utilized RCV for its municipal elections.', 'https://nj.gov/state/elections/', 'New Jersey Division of Elections / FairVote', '2026-05-17', 'static', 'secondary_source', 'All candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('a57e007bc6216f24', 'NJ', '["federal","state","county"]', 'runoff_rules', 'How are exact ties broken in New Jersey elections?', '["How are tied elections decided in New Jersey?","Tie-breaker rules New Jersey elections","What happens if a race is tied in NJ?"]', 'Under N.J.S.A. 19:3-25, an exact tie in a general or primary election results in a ''failure to elect,'' essentially creating a vacancy in that office. The vacancy is then filled according to the standard vacancy procedures for that specific office, which typically involves a special election or a temporary appointment by the relevant party committee or Governor.', 'https://law.justia.com/codes/new-jersey/title-19/section-19-3-25/', 'New Jersey Statutes Annotated 19:3-25', '2026-05-17', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('4e19be2a29c6d2af', 'NJ', '["state","county","municipal"]', 'finance_ethics', 'What disclaimer language is required on New Jersey campaign materials?', '["New Jersey ''Paid for by'' rules","Campaign ad disclaimer requirements NJ","Political taglines New Jersey ELEC"]', 'New Jersey campaign finance law requires all political advertising and campaign material to include a clear ''Paid for by'' disclaimer. The disclaimer must identify the name and business address of the candidate, committee, or individual that authorized and financed the communication.', 'https://www.elec.nj.gov/pdffiles/compliance_manuals/manual_c.pdf', 'New Jersey ELEC - Compliance Manual', '2026-05-17', 'static', 'official_source_direct', 'All candidates and PACs', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('839a3f4a84da7b24', 'NJ', '["state","county","municipal"]', 'finance_ethics', 'When does outside spending become prohibited coordination in New Jersey?', '["NJ campaign coordination rules","When is a PAC expenditure not independent in New Jersey?","Prohibition on candidate-PAC coordination NJ"]', 'An independent expenditure becomes ''coordinated'' if it is made in cooperation, consultation, or concert with, or at the request or suggestion of, a candidate or their committee. Once coordinated, the expenditure constitutes an in-kind contribution and is subject to the strict per-election contribution limits.', 'https://www.elec.nj.gov/pdffiles/compliance_manuals/manual_c.pdf', 'New Jersey ELEC', '2026-05-17', 'static', 'official_source_direct', 'All candidates and IECs', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('ef477f7eb74cafa3', 'NJ', '["state","county","municipal"]', 'finance_ethics', 'What are the penalties for late campaign finance filings in New Jersey?', '["NJ ELEC late fee","Penalty for missing a New Jersey campaign finance deadline","ELEC fine for late filing NJ"]', 'The New Jersey Election Law Enforcement Commission (ELEC) has the authority to assess civil penalties for late reports or filing violations. Fines can be substantial, up to $9,900 for a first offense and more for subsequent offenses, depending on the severity of the violation and the amount of money involved.', 'https://www.elec.nj.gov/', 'New Jersey ELEC', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('6352c7c831b5cdc3', 'NJ', '["state","county","municipal"]', 'finance_ethics', 'When and how must a New Jersey campaign committee terminate?', '["Closing a New Jersey campaign committee","ELEC committee termination requirements","Final campaign finance report New Jersey"]', 'A candidate committee may formally terminate when it has achieved a zero cash balance, legally disposed of all unexpended funds, and resolved all outstanding debts or loans. A formal Final Report marking the campaign account as closed must be filed with ELEC.', 'https://www.elec.nj.gov/pdffiles/compliance_manuals/manual_c.pdf', 'New Jersey ELEC', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('8984dd3ac3fda372', 'NJ', '["state","county","municipal"]', 'finance_ethics', 'How are in-kind contributions valued and reported in New Jersey?', '["New Jersey in-kind contribution valuation rules","Reporting non-monetary donations New Jersey campaign","Fair market value for in-kind gifts NJ"]', 'In-kind contributions (donated goods, services, or equipment) must be reported to ELEC at their fair market value. The value of in-kind contributions counts directly toward the donor''s per-election monetary contribution limit.', 'https://www.elec.nj.gov/pdffiles/compliance_manuals/manual_c.pdf', 'New Jersey ELEC', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('52cf575625d15f2d', 'NJ', '["state","county","municipal"]', 'finance_ethics', 'Are there limits on a candidate loaning personal funds to their own campaign in New Jersey?', '["New Jersey candidate personal loan limits","Can I pay myself back for a campaign loan in NJ?","Reporting candidate loans in ELEC"]', 'A candidate may loan or contribute an UNLIMITED amount of their own personal funds to their campaign committee; these funds are exempt from standard contribution limits. Loans must be properly documented on disclosures and may be repaid from campaign contributions raised during the cycle.', 'https://www.elec.nj.gov/pdffiles/compliance_manuals/manual_c.pdf', 'New Jersey ELEC', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('30d94fd62295cc1e', 'NJ', '["state","county","municipal"]', 'finance_ethics', 'What can New Jersey candidates do with unexpended campaign funds?', '["What can I do with leftover campaign money in NJ?","NJ surplus campaign funds rules","Donating remaining campaign funds New Jersey"]', 'Unexpended campaign funds cannot be converted to personal use. Candidates may retain surplus funds for a future campaign, return them pro-rata to contributors, transfer them to a recognized political party, or donate them to an IRS-recognized tax-exempt charitable organization.', 'https://www.elec.nj.gov/pdffiles/compliance_manuals/manual_c.pdf', 'New Jersey ELEC', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('279a4f02a5e37af8', 'NJ', '["county"]', 'election_dates', 'What are the terms and election cycles for county offices in New Jersey?', '["When are county executives elected in NJ?","New Jersey county official term lengths","Are county commissioners on the 2026 ballot?"]', 'In New Jersey, County Commissioners (formerly Freeholders) and County Sheriffs serve three-year terms. County Clerks and Surrogates serve five-year terms. Because these terms are staggered across odd and even years, many of these county offices will be featured prominently on the 2026 midterm ballot.', 'https://nj.gov/state/elections/candidate-information.shtml', 'New Jersey Division of Elections', '2026-05-17', 'per_cycle', 'official_source_direct', 'County candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('0261cca04872fcb8', 'NJ', '["municipal"]', 'election_dates', 'When are municipal elections held in New Jersey?', '["New Jersey May municipal elections","When are mayors elected in NJ?","Nonpartisan municipal election cycle New Jersey"]', 'While many New Jersey municipalities hold their elections concurrently with the November general election, numerous municipalities utilizing nonpartisan forms of government (such as Newark and Trenton) hold their municipal elections on the second Tuesday in May. Many of these operate on an odd-year or four-year cycle independent of federal races.', 'https://nj.gov/state/elections/election-chronological-timelines.shtml', 'New Jersey Division of Elections - Timelines', '2026-05-17', 'static', 'official_source_direct', 'Local candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('14b654217b5a7173', 'NJ', '["state","county","municipal"]', 'election_dates', 'What is the canvassing and certification timeline for New Jersey elections?', '["When are New Jersey election results official?","NJ certification deadline","Board of State Canvassers meeting New Jersey"]', 'County Boards of Canvassers meet shortly after the election (typically the Monday following Election Day) to begin officially certifying local results. The Board of State Canvassers subsequently meets on or before the 28th day after the election to certify statewide and federal election returns.', 'https://nj.gov/state/elections/election-chronological-timelines.shtml', 'New Jersey Division of Elections', '2026-05-17', 'static', 'official_source_direct', 'All candidates and campaigns', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('f440c30d6b646f2e', 'NJ', '["federal","state"]', 'election_dates', 'When and how are special elections called in New Jersey?', '["New Jersey special election timeline","Who calls a special election to fill a US House vacancy in NJ?","Filling a midterm vacancy New Jersey"]', 'For a U.S. Senate vacancy, the Governor may appoint a temporary replacement and schedule a special election. For the State Legislature, a vacancy is initially filled within 35 days by a temporary appointment from the vacating member''s county political party committee, followed by a special election if sufficient time remains in the term.', 'https://nj.gov/state/elections/', 'New Jersey Division of Elections', '2026-05-17', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('8da1561990cdfb79', 'NJ', '["state"]', 'election_dates', 'What is the equivalent of the State Board of Elections in New Jersey?', '["Who certifies statewide elections in NJ?","New Jersey Division of Elections structure","Who oversees the county boards of elections in NJ?"]', 'New Jersey does not have a traditional ''State Board of Elections.'' Election administration is overseen by the Division of Elections, which operates under the Secretary of State. The official certification of statewide results is handled by the Board of State Canvassers, comprising the Governor and four state senators.', 'https://nj.gov/state/elections/about.shtml', 'New Jersey Division of Elections', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T19-28-04_new_jersey_full_v1'),
  ('abbcd269c446f6e1', 'NJ', '["federal","state","county","municipal"]', 'election_dates', 'What are the specific dates for early in-person voting in New Jersey for 2026?', '["When is early voting for the New Jersey primary 2026?","NJ early voting dates 2026 general election","How many days of early voting in New Jersey?"]', 'For the 2026 cycle, early voting for the primary election runs for 5 days, from Wednesday, May 27 through Sunday, May 31. For the general election, early voting runs for 9 days, from Saturday, October 24 through Sunday, November 1. Polls are open daily during these windows.', 'https://nj.gov/state/elections/vote-early-voting.shtml', 'New Jersey Division of Elections - Early Voting', '2026-05-17', 'per_cycle', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T19-28-04_new_jersey_full_v1')
